(function () {
  function threshold(modifiers) {
    if (modifiers.includes("full")) {
      return 0.99;
    }
    if (modifiers.includes("half")) {
      return 0.5;
    }
    const thresholdIndex = modifiers.indexOf("threshold");
    if (thresholdIndex === -1) {
      return 0;
    }
    const raw = modifiers[thresholdIndex + 1] || "";
    const digits = raw.replace(/[^0-9]/g, "");
    return digits ? Number(digits) / 100 : 0;
  }

  function marginToken(token) {
    if (token.endsWith("px") || token.endsWith("%")) {
      return token;
    }
    if (/^-?\d+$/.test(token)) {
      return `${token}px`;
    }
    return token;
  }

  function rootMargin(modifiers) {
    const marginIndex = modifiers.indexOf("margin");
    if (marginIndex === -1) {
      return "0px 0px 0px 0px";
    }
    const parts = [];
    for (let index = marginIndex + 1; index < modifiers.length; index += 1) {
      const token = modifiers[index];
      if (["once", "half", "full", "threshold", "leave", "enter"].includes(token)) {
        break;
      }
      parts.push(marginToken(token));
    }
    return parts.length ? parts.join(" ") : "0px 0px 0px 0px";
  }

  document.addEventListener("alpine:init", () => {
    Alpine.directive(
      "intersect",
      Alpine.skipDuringClone((element, { value, modifiers, expression }, { evaluateLater, cleanup }) => {
        const evaluate = evaluateLater(expression);
        const options = {
          threshold: threshold(modifiers),
          rootMargin: rootMargin(modifiers),
        };
        const triggerOnLeave = value === "leave";
        let hasTriggered = false;

        const observer = new IntersectionObserver((entries) => {
          entries.forEach((entry) => {
            const inView = entry.isIntersecting && entry.intersectionRatio >= options.threshold;
            const shouldRun = triggerOnLeave ? !inView : inView;
            if (!shouldRun) {
              return;
            }
            if (modifiers.includes("once") && hasTriggered) {
              observer.disconnect();
              return;
            }
            hasTriggered = true;
            evaluate();
            if (modifiers.includes("once")) {
              observer.disconnect();
            }
          });
        }, options);

        observer.observe(element);
        cleanup(() => observer.disconnect());
      })
    );
  });
})();
